class MyAccountSubPageLayout {
    defaultPage;
    constructor(defaultPage) {
        this.defaultPage = defaultPage;
        $(() => {
            this.bindEvents();
        });
    }

    bindEvents() {
       this.clickEvent();
       this.handleSubPageValue()
    }

    handleSubPageValue() {
        const paramsString = location.search;
        const searchParams = new URLSearchParams(paramsString);
        let indexParam = searchParams.get('sub-page');
        if (indexParam) {
            this.clearActiveStatus();
            this.loadPage(indexParam);
            $(`a[data-href$=${indexParam}]`).parent().addClass('active');
        } else {
            this.loadPage(this.defaultPage);
        }
    }

    clickEvent() {
        const me = this;
        $(".page-submenu-item").click(function (event) {
            event.preventDefault();
            const pageSlug= $(this).children('a').attr('data-href');
            // $(".loader-circle").show();
            me.loadPage(pageSlug);
            me.clearActiveStatus();
            $(this).addClass('active');
            me.updatePageUrl(pageSlug)
        })
    }



    loadPage(pageSlug) {
        const me = this;
        let url;
        url = this.buildProperUrlForPageLoading(pageSlug);
        $.ajax({
            url,
            data: {},
            type: "GET",
            dataType: "html",
            success: function (data) {
                me.insertLoadedPageIntoPage(data);
            },
            error: function (xhr, status) {
                alert("Sorry, there was a problem!");
            },
            complete: function (xhr, status) {
                me.refreshBreadcrumb(pageSlug);
                new OrderDetailLayout();
                new AddressEditLayout();
                new PersonalDataEditLayout();
                new BannerGeneratorForm();
            }
        });
    }

    refreshBreadcrumb() {
        const nameOfPage =  $('#page-load h2').html();
        const breadcrumb = $('#breadcrumb');
        $('.current-page').empty();
        breadcrumb.append(`<a class="current-page"><span>${nameOfPage}</span></a>`);
    }

    buildProperUrlForPageLoading(pageSlug) {
        return `/customer/${pageSlug}`
    }

    insertLoadedPageIntoPage(data) {
        $('#page-load').hide();
        $('#page-load').html(data);
        $('#page-load').show(500);
    }

    clearActiveStatus() {
        $(".page-submenu-item").removeClass('active');
    }

    updatePageUrl(pageSlug){
        window.history.pushState({},"", `?sub-page=${pageSlug}`);
    }

}